#!/usr/bin/env bash
# workflow-1.sh — 组合搭建与管理主工作流（端到端，最重要） SOP walkthrough for 个人投资理财.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="个人投资理财"
WORKFLOW="组合搭建与管理主工作流（端到端，最重要）"

usage() {
  cat <<EOF
workflow-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-1.sh             # interactive
  ./workflow-1.sh --dry-run
  ./workflow-1.sh --json
  ./workflow-1.sh --explain
  ./workflow-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "组合搭建与管理主工作流（端到端，最重要）" 工作流。

一句话: 从「我有钱想投资但不知从何下手」到「一个低成本、税务高效、自动化、能长期管住手的组合」—— 本行业**最核心、最高复用**的元工作流，价值/被动/技术/趋势四派都把它当地基（分歧只在「选品」一步往哪走）。

入门 SOP 共 8 步, 失败模式自检 5 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定目标 / 时间轴 / 风险承受度**：写下「为什么投、什么时候要用钱、跌 30% 会不会半夜割肉」。风险承受度 = 意愿(心理) × 能力(时间轴/收入稳定性) × 需求(目标)。(evidence: [T03-S002, T03-S012])"
  "**定资产配置（股 / 债 / 现金比）**：先定大类权重（如 80/20、60/40），再谈具体标的。学术与实务共识：长期回报主要由配置而非选股/择时决定。常用启发：股票% ≈ 「110/120 − 年龄」或按风险承受度问卷，但**是启发不是定律**。(evidence: [T03-S002, T03-S012])"
  "**账户结构先于产品**（本工作流最被低估、资深最看重的一步）：先选对**税优容器**再谈买什么。"
  "**选品（宽基指数 vs 主动）**：装进容器的产品。被动默认 = 低费率宽基（三基金：美股全市场 VTI + 国际 VXUS + 债 BND；或单只全球 VT；CN：沪深300/标普500 QDII + 宽基指基）。想主动选股 → 转 Workflow 2/4/5。(evidence: [T03-S004, T03-S010])"
  "**执行（定投 DCA vs 一次性 lump sum）**：有一大笔闲钱 → 研究显示因 time-in-market，多数历史区间 **lump-sum 期望回报 > 把同一笔钱分期 DCA**；但 DCA 降低后悔/情绪风险。靠工资持续投 = 天然定投。(evidence: [T03-S005])"
  "**再平衡（阈值 / 日历）**：设触发规则把偏离的权重拉回（卖涨买跌）。详见 Workflow 6。(evidence: [T03-S006])"
  "**年度复盘 + 税损收割**：每年看一次配置漂移、费率、目标变化；应税账户顺手做 TLH。详见 Workflow 6。(evidence: [T03-S007])"
  "**行为纪律（stay the course）**：写下「市场跌 X% 时我不动/继续定投」的预案，把决策从情绪手里拿走。(evidence: [T03-S001, T03-S016])"
)
declare -a FAILURE_MODES=(
  "**先选产品后想账户**：开了 taxable 买基金，却没拿满 401k 雇主匹配 —— 等于每年白扔一份「保证 100% 回报」。自检：你拿满雇主匹配了吗？"
  "**配置与风险承受度不匹配**：纸面接受「长期投资」，实际 80% 股票在 −30% 时半夜清仓。自检：你写下「跌 X% 我也不卖」的预案了吗？"
  "**被费率慢性放血**：长期持有 1%+ 费率的主动基金/含申购费产品，30 年吃掉巨量复利却不自知。自检：你用 Morningstar/Empower 查过整体加权费率吗？"
  "**定投瘫痪 / 等更好时点**：有一笔闲钱却迟迟不入场择时，踏空。自检：你设了自动定投把决策自动化了吗？"
  "**从不再平衡**：牛市后股票占比失控，下次回撤痛感远超预期。自检：你定了再平衡触发规则（日历或 5/25）吗？"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-1-walkthrough"
fi
